#include <iostream>
#include <algorithm>
using namespace std;
struct person
{
    int exam,num;
};
person a[5005];
bool cmp(person x,person y)
{
    if(x.exam!=y.exam)
    {
        return x.exam>y.exam;
    }
    else
    {
        return x.num<y.num;
    }
}
int main()
{
    int n,m;
    cin>>n>>m;
    for(int i=0;i<=n-1;i++)
    {
        cin>>a[i].num>>a[i].exam;
    }
    sort(a,a+n,cmp);
    m*=1.5;
    while(a[m-1].exam==a[m].exam&&m<n)
    {
        m++;
    }
    cout<<a[m-1].exam<<" "<<m<<endl;
    for(int i=0;i<=m-1;i++)
    {
        cout<<a[i].num<<" "<<a[i].exam<<endl;
    }
    return 0;
}
